mapper.select:
SELECT 
FROM tb_vmd_outbox t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.event_id = #{eventId}


    AND t.event_type = #{eventType}


    AND t.aggregate_type = #{aggregateType}


    AND t.aggregate_id = #{aggregateId}


    AND t.publish_state = #{publishState}


    AND t.source_type = #{sourceType}


    AND t.source_ref_id = #{sourceRefId}

ORDER BY t.id DESC
